// UploadRFID.js - RFID Excel uploader for /upload-rfid route
// Uses clientCode from localStorage and uploads via multipart/form-data
import React, { useRef, useState, useEffect } from 'react';
import { FaCloudUploadAlt, FaFileExcel, FaTimes, FaCheckCircle } from 'react-icons/fa';
import Header from './Header';

const API_URL = 'https://testing.loyalstring.co.in/api/Device/ImportRFIDData';

const UploadRFID = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploading, setUploading] = useState(false);
  const [success, setSuccess] = useState(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef();
  const [userInfo, setUserInfo] = useState(null);

  // Get clientCode and userInfo from localStorage
  let clientCode = '';
  useEffect(() => {
    try {
      const user = JSON.parse(localStorage.getItem('userInfo'));
      setUserInfo(user);
      clientCode = user?.ClientCode || '';
    } catch {}
  }, []);
  try {
    const user = JSON.parse(localStorage.getItem('userInfo'));
    clientCode = user?.ClientCode || '';
  } catch {}

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && (file.name.endsWith('.xlsx') || file.name.endsWith('.xls'))) {
      setSelectedFile(file);
      setError('');
      setSuccess(null);
    } else {
      setError('Please select a valid Excel file (.xlsx or .xls)');
      setSelectedFile(null);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      if (file && (file.name.endsWith('.xlsx') || file.name.endsWith('.xls'))) {
        setSelectedFile(file);
        setError('');
        setSuccess(null);
      } else {
        setError('Please select a valid Excel file (.xlsx or .xls)');
        setSelectedFile(null);
      }
    }
  };

  const handleDragOver = (e) => {
    e.preventDefault();
  };

  const handleBrowseClick = () => {
    fileInputRef.current.click();
  };

  const handleRemoveFile = () => {
    setSelectedFile(null);
    setUploadProgress(0);
    setSuccess(null);
    setError('');
  };

  // For progress bar, use xhr
  const uploadWithProgress = () => {
    if (!selectedFile || !clientCode) return;
    setUploading(true);
    setUploadProgress(0);
    setError('');
    setSuccess(null);
    const formData = new FormData();
    formData.append('ClientCode', clientCode);
    formData.append('file', selectedFile);
    const xhr = new XMLHttpRequest();
    xhr.open('POST', API_URL);
    xhr.upload.onprogress = (e) => {
      if (e.lengthComputable) {
        setUploadProgress(Math.round((e.loaded / e.total) * 100));
      }
    };
    xhr.onload = () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        setSuccess('File uploaded successfully!');
        setSelectedFile(null);
      } else {
        setError('Upload failed. Please try again.');
      }
      setUploading(false);
      setUploadProgress(100);
    };
    xhr.onerror = () => {
      setError('Upload failed. Please try again.');
      setUploading(false);
    };
    xhr.send(formData);
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #f7f8fa 0%, #e0e7ef 100%)', fontFamily: 'Poppins, Inter, sans-serif' }}>
      <Header userInfo={userInfo} />
      <div style={{ maxWidth: 600, margin: '0 auto', padding: '48px 0 0 0' }}>
        <div className="text-center" style={{ marginBottom: 18 }}>
          <h1 style={{
            fontWeight: 800,
            fontSize: 30,
            color: '#5470FF',
            letterSpacing: 0.5,
            marginBottom: 8,
            textAlign: 'center',
            textShadow: '0 2px 8px #5470ff11',
            borderBottom: '3px solid #5470FF',
            display: 'inline-block',
            paddingBottom: 6
          }}>
            Upload Sheet to Add RFID Tags
          </h1>
          <div style={{ fontSize: 17, color: '#444', fontWeight: 500, marginTop: 16, marginBottom: 8, textAlign: 'center', lineHeight: 1.5 }}>
            Upload your Excel file to quickly add multiple RFID tags to your inventory.<br />
            Only .xlsx or .xls files are supported.
          </div>
        </div>
        <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'flex-start', minHeight: 420 }}>
          <div style={{ background: '#fff', borderRadius: 24, boxShadow: '0 10px 40px 0 rgba(31, 38, 135, 0.10)', padding: '2.5rem 2.5rem 2rem 2.5rem', minWidth: 400, maxWidth: 440, width: '100%' }}>
            <div style={{ fontWeight: 600, color: '#888', fontSize: 15, marginBottom: 18, letterSpacing: 0.2 }}>FILE UPLOADER</div>
            <div
              onDrop={handleDrop}
              onDragOver={handleDragOver}
              style={{
                background: '#f8fafc',
                border: '2.5px dashed #b2e0e6',
                borderRadius: 18,
                padding: '2.2rem 1.2rem',
                textAlign: 'center',
                marginBottom: 18,
                cursor: 'pointer',
                transition: 'border 0.2s',
              }}
              onClick={handleBrowseClick}
            >
              <FaCloudUploadAlt size={48} style={{ color: '#5470FF' }} />
              <div style={{ margin: '18px 0 8px 0', fontWeight: 500, color: '#444', fontSize: 17 }}>Drag and drop your files here</div>
              <div style={{ color: '#aaa', fontSize: 14, marginBottom: 10 }}>OR</div>
              <button
                type="button"
                style={{
                  background: '#5470FF',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 8,
                  padding: '10px 28px',
                  fontWeight: 600,
                  fontSize: 15,
                  cursor: 'pointer',
                  boxShadow: '0 2px 8px #5470ff11',
                  marginBottom: 0,
                  fontFamily: 'Poppins, Inter, sans-serif',
                  transition: 'background 0.2s',
                }}
                onClick={e => { e.stopPropagation(); handleBrowseClick(); }}
                disabled={uploading}
              >
                Browse files
              </button>
              <input
                type="file"
                accept=".xlsx,.xls"
                ref={fileInputRef}
                style={{ display: 'none' }}
                onChange={handleFileChange}
                disabled={uploading}
              />
            </div>
            {/* File preview and progress */}
            {selectedFile && (
              <div style={{ background: '#f8fafc', borderRadius: 12, padding: '1rem 1.2rem', marginBottom: 18, display: 'flex', alignItems: 'center', gap: 12, position: 'relative' }}>
                <FaFileExcel size={32} style={{ color: '#7b4be3', background: '#e6e6fa', borderRadius: 8, padding: 4 }} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 15, color: '#333', marginBottom: 2 }}>{selectedFile.name}</div>
                  <div style={{ fontSize: 13, color: '#888', marginBottom: 6 }}>{(selectedFile.size / 1024).toFixed(0)} kb</div>
                  <div style={{ height: 7, background: '#e0e7ef', borderRadius: 6, overflow: 'hidden', marginBottom: 2 }}>
                    <div style={{ width: `${uploadProgress}%`, height: '100%', background: 'linear-gradient(90deg, #3ed1c8, #7b4be3)', borderRadius: 6, transition: 'width 0.3s' }}></div>
                  </div>
                </div>
                {!uploading && (
                  <button onClick={handleRemoveFile} style={{ background: 'none', border: 'none', color: '#e74c3c', fontSize: 20, cursor: 'pointer', marginLeft: 6 }}><FaTimes /></button>
                )}
              </div>
            )}
            {/* Upload button */}
            {selectedFile && (
              <button
                type="button"
                style={{
                  background: uploading ? '#b2e0e6' : 'linear-gradient(90deg, #3ed1c8, #7b4be3)',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 8,
                  padding: '10px 28px',
                  fontWeight: 700,
                  fontSize: 15,
                  cursor: uploading ? 'not-allowed' : 'pointer',
                  boxShadow: '0 2px 8px #7b4be311',
                  width: '100%',
                  marginBottom: 10,
                  fontFamily: 'Poppins, Inter, sans-serif',
                  transition: 'background 0.2s',
                }}
                onClick={uploadWithProgress}
                disabled={uploading}
              >
                {uploading ? 'Uploading...' : 'Upload'}
              </button>
            )}
            {/* Success/Error messages */}
            {success && (
              <div style={{ color: '#2ecc71', fontWeight: 600, marginTop: 10, display: 'flex', alignItems: 'center', gap: 6 }}><FaCheckCircle /> {success}</div>
            )}
            {error && (
              <div style={{ color: '#e74c3c', fontWeight: 600, marginTop: 10 }}>{error}</div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default UploadRFID;
